#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long val,lson,rson;
    long long add_tag,mul_tag;
}a[600010];
long long c[600010],h[600010],dep[600010],pos[600010],ans[600010],op[600010],val[600010];
void pushadd(long long x,long long v)
{
    if(!x)
    {
        return;
    }
    a[x].val+=v;
    a[x].add_tag+=v;
}
void pushmul(long long x,long long v)
{
    if(!x)
    {
        return;
    }
    a[x].val*=v;
    a[x].mul_tag*=v;
    a[x].add_tag*=v;
}
void pushdown(int x)
{
    if(a[x].mul_tag!=1)
    {
        pushmul(a[x].lson,a[x].mul_tag);
        pushmul(a[x].rson,a[x].mul_tag);
        a[x].mul_tag=1;
    }
    if(a[x].add_tag!=0)
    {
        pushadd(a[x].lson,a[x].add_tag);
        pushadd(a[x].rson,a[x].add_tag);
        a[x].add_tag=0;
    }
}
long long dis[600010],b[600010],l[600010],fa[600010],sum[600010],siz[600010],root[600010];
long long merge(long long x,long long y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    pushdown(x);
    pushdown(y);
    if(a[x].val>a[y].val)
    {
        swap(x,y);
    }
    a[x].rson=merge(a[x].rson,y);
    if(dis[a[x].lson]<dis[a[x].rson])
    {
        swap(a[x].lson,a[x].rson);
    }
    dis[x]=dis[a[x].rson]+1;
    return x;
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&h[i]);
    }
    dep[1]=0;
    dep[0]=-1;
    for(long long i=2;i<=n;i++)
    {
        scanf("%lld%lld%lld",&fa[i],&op[i],&val[i]);
        dep[i]=dep[fa[i]]+1;
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&a[i].val,&c[i]);
        root[c[i]]=merge(root[c[i]],i);
        a[i].mul_tag=1;
    }
    dis[0]=-1;
    for(long long i=n;i>=1;i--)
    {
        while(root[i])
        {
            if(a[root[i]].val<h[i])
            {
                pos[root[i]]=i;
                pushdown(root[i]);
                root[i]=merge(a[root[i]].lson,a[root[i]].rson);
            }
            else
            {
                break;
            }
        }
        if(i==1)
        {
            break;
        }
        if(root[i])
        {
            if(op[i]==0)
            {
                pushadd(root[i],val[i]);
            }
            else
            {
                pushmul(root[i],val[i]);
            }
            pushdown(root[i]);
            root[fa[i]]=merge(root[fa[i]],root[i]);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        ans[pos[i]]++;
    }
    for(long long i=1;i<=n;i++)
    {
        printf("%lld\n",ans[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",dep[c[i]]-dep[pos[i]]);
    }
    return 0;
}
